define i1 @class_normal_or_fcmp_oeq_zero(half %x) {
  %oeq.inf = fcmp oeq half %x, 0xH0000
  %class = call i1 @llvm.is.fpclass.f16(half %x, i32 264)
  %or = or i1 %oeq.inf, %class
  ret i1 %or
}

define i1 @class_normal_or_fcmp_ueq_zero(half %x) {
  %ueq.inf = fcmp ueq half %x, 0xH0000
  %class = call i1 @llvm.is.fpclass.f16(half %x, i32 264)
  %or = or i1 %ueq.inf, %class
  ret i1 %or
}

define i1 @fcmp_ueq_zero_or_class_normal(half %x) {
  %ueq.inf = fcmp ueq half %x, 0xH0000
  %class = call i1 @llvm.is.fpclass.f16(half %x, i32 264)
  %or = or i1 %ueq.inf, %class
  ret i1 %or
}

define i1 @fcmp_oeq_neginf_or_oge_zero_f16(half %x) {
  %cmpinf = fcmp oeq half %x, 0xHFC00
  %cmp.oge.zero = fcmp oge half %x, 0xH0000
  %class = or i1 %cmp.oge.zero, %cmpinf
  ret i1 %class
}

define i1 @fcmp_oeq_neginf_or_ogt_zero_f16(half %x) {
  %cmpinf = fcmp oeq half %x, 0xHFC00
  %cmp.ogt.zero = fcmp ogt half %x, 0xH0000
  %class = or i1 %cmp.ogt.zero, %cmpinf
  ret i1 %class
}

